if(compareSemver('1.0.0','1.0.0')!==0)throw new Error('equal versions')
if(compareSemver('1.0.0','2.0.0')!==-1)throw new Error('major order')
if(compareSemver('1.10.0','1.9.0')!==1)throw new Error('minor compares numerically, not lexically')
if(compareSemver('1.0.0-alpha','1.0.0')!==-1)throw new Error('prerelease < release')
if(compareSemver('1.0.0','1.0.0-alpha')!==1)throw new Error('release > prerelease')
if(compareSemver('1.0.0-alpha','1.0.0-alpha.1')!==-1)throw new Error('shorter prerelease prefix is lower')
if(compareSemver('1.0.0-alpha.1','1.0.0-alpha.beta')!==-1)throw new Error('numeric identifier < alphanumeric')
if(compareSemver('1.0.0-alpha.beta','1.0.0-beta')!==-1)throw new Error('alphanumeric compares lexically')
if(compareSemver('1.0.0-beta.2','1.0.0-beta.11')!==-1)throw new Error('numeric identifiers compare as numbers')
if(compareSemver('1.0.0-beta.11','1.0.0-beta.2')!==1)throw new Error('symmetric numeric compare')
if(compareSemver('1.0.0-rc.1','1.0.0-rc.1')!==0)throw new Error('equal prereleases')

if(parseDuration('PT0S')!==0)throw new Error('zero seconds')
if(parseDuration('P1D')!==86400)throw new Error('one day')
if(parseDuration('PT1H2M3S')!==3723)throw new Error('h+m+s')
if(parseDuration('P1DT1S')!==86401)throw new Error('day + second across T')
if(parseDuration('PT90M')!==5400)throw new Error('minutes need no normalization')
if(parseDuration('PT0.5S')!==0.5)throw new Error('fractional seconds')
if((()=>{try{parseDuration('P1M');return true}catch(e){return false}})())throw new Error('P1M is months — must throw')
if((()=>{try{parseDuration('P');return true}catch(e){return false}})())throw new Error('bare P must throw')
if((()=>{try{parseDuration('PT');return true}catch(e){return false}})())throw new Error('dangling T must throw')
if((()=>{try{parseDuration('1H');return true}catch(e){return false}})())throw new Error('missing P must throw')
if((()=>{try{parseDuration('P1Y');return true}catch(e){return false}})())throw new Error('years must throw')

if(JSON.stringify(mergeIntervals([[1,3],[2,6],[8,10]]))!=='[[1,6],[8,10]]')throw new Error('basic overlap merge')
if(JSON.stringify(mergeIntervals([[1,2],[2,3]]))!=='[[1,3]]')throw new Error('touching intervals merge')
if(JSON.stringify(mergeIntervals([[1,10],[2,3]]))!=='[[1,10]]')throw new Error('nested interval absorbed')
if(JSON.stringify(mergeIntervals([[8,10],[1,3]]))!=='[[1,3],[8,10]]')throw new Error('unsorted input handled + output sorted')
if(JSON.stringify(mergeIntervals([[-5,-2],[-3,0]]))!=='[[-5,0]]')throw new Error('negative bounds')
if(JSON.stringify(mergeIntervals([[4,4],[4,4]]))!=='[[4,4]]')throw new Error('duplicate point intervals')
if(JSON.stringify(mergeIntervals([]))!=='[]')throw new Error('empty input')
if(JSON.stringify(mergeIntervals([[7,9]]))!=='[[7,9]]')throw new Error('single interval untouched')
const _inp=[[5,6],[1,2]];mergeIntervals(_inp);if(JSON.stringify(_inp)!=='[[5,6],[1,2]]')throw new Error('input array was mutated')

if(JSON.stringify(parseCsvLine('a,b,c'))!=='["a","b","c"]')throw new Error('plain fields')
if(JSON.stringify(parseCsvLine('a,"b,c",d'))!=='["a","b,c","d"]')throw new Error('quoted field with comma')
const _q=parseCsvLine('a,"he said ""hi""",b');if(_q.length!==3||_q[1]!=='he said "hi"'||_q[2]!=='b')throw new Error('escaped quotes inside quoted field')
if(JSON.stringify(parseCsvLine('a,,b'))!=='["a","","b"]')throw new Error('empty middle field')
if(JSON.stringify(parseCsvLine('a,b,'))!=='["a","b",""]')throw new Error('trailing comma → trailing empty field')
if(JSON.stringify(parseCsvLine(''))!=='[""]')throw new Error('empty line → one empty field')
if(JSON.stringify(parseCsvLine('""'))!=='[""]')throw new Error('bare quoted empty field')
if(JSON.stringify(parseCsvLine(' a ,b'))!=='[" a ","b"]')throw new Error('unquoted whitespace preserved')
if(JSON.stringify(parseCsvLine('"x"'))!=='["x"]')throw new Error('single quoted field')
